const meeting = $input.first().json;
const meetings = meeting.meetings || [];
const results = [];
for (const m of meetings) {
  const files = m.recording_files || [];
  const vtt = files.find(f => f.file_type === 'TRANSCRIPT');
  if (vtt) {
    results.push({ json: {
      platform: 'zoom',
      meeting_id: m.uuid,
      topic: m.topic,
      start_time: m.start_time,
      duration: m.duration,
      host_email: m.host_email,
      transcript_url: vtt.download_url
    }});
  }
}
return results;

const vttRaw = $input.first().json.data || '';
const lines = vttRaw.split('\n');
const textLines = [];
for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed || trimmed === 'WEBVTT' || /^\d+$/.test(trimmed) || /-->/.test(trimmed)) continue;
  textLines.push(trimmed);
}
const prev = $('Zoom: Extract Transcript URL').first().json;
return [{ json: {
  platform: prev.platform,
  topic: prev.topic,
  start_time: prev.start_time,
  duration: prev.duration,
  host: prev.host_email,
  transcript_text: textLines.join(' ')
}}];

const files = $input.first().json.files || [];
return files.map(f => ({ json: {
  file_id: f.id,
  file_name: f.name,
  modified_time: f.modifiedTime,
  owner: (f.owners || [{}])[0].emailAddress || 'unknown'
}}));

const vttRaw = $input.first().json.data || '';
const lines = vttRaw.split('\n');
const textLines = [];
for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed || trimmed === 'WEBVTT' || /^\d+$/.test(trimmed) || /-->/.test(trimmed)) continue;
  textLines.push(trimmed);
}
const meta = $('Meet: Split Files').first().json;
const topicGuess = meta.file_name.replace('.vtt','').replace(/_/g,' ').replace(/-transcript$/i,'').trim();
return [{ json: {
  platform: 'google_meet',
  topic: topicGuess,
  start_time: meta.modified_time,
  duration: null,
  host: meta.owner,
  transcript_text: textLines.join(' ')
}}];

const now = new Date();
return [{ json: {
  subject: `[MeetCore] No recordings found — ${now.toLocaleDateString('en-US', {weekday:'long', month:'long', day:'numeric'})}`,
  checked_at: now.toLocaleTimeString('en-US', {hour:'2-digit', minute:'2-digit'}),
  checked_date: now.toLocaleDateString('en-US', {weekday:'long', month:'long', day:'numeric', year:'numeric'}),
  platforms: 'Zoom · Google Meet'
}}];

values.content:
=You are a professional meeting analyst. Analyze the following meeting transcript and return a JSON object with these exact keys:
- summary: 3-5 sentence executive summary
- decisions: array of strings (key decisions made)
- action_items: array of objects with {task, owner, deadline}
- follow_up_required: boolean
- follow_up_notes: string (what to cover in follow-up, or empty string)
- key_topics: array of strings (main topics discussed)
- platform: pass through the platform value from input
- topic: pass through the meeting topic
- start_time: pass through the start_time
- host: pass through the host

Return ONLY valid JSON, no markdown fences.

Platform: {{ $json.platform }}
Meeting: {{ $json.topic }}
Date: {{ $json.start_time }}
Host: {{ $json.host }}

Transcript:
{{ $json.transcript_text.slice(0, 12000) }}

parameters.jsCode:
const raw = $input.first().json.message?.content || $input.first().json.content || '';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {summary:'Parse error',decisions:[],action_items:[],follow_up_required:false,follow_up_notes:'',key_topics:[]};
}
return [{json: parsed}];

const d = $input.first().json;
const platformLabel = {zoom:'Zoom',google_meet:'Google Meet',microsoft_teams:'Microsoft Teams',slack:'Slack'}[d.platform] || d.platform;
const platformIcon = {zoom:'🎥',google_meet:'📹',microsoft_teams:'💼',slack:'💬'}[d.platform] || '📅';
const actionRows = (d.action_items || []).map(a => `<tr><td style="padding:8px 12px;border-bottom:1px solid #e8e4e6;">${a.task||''}</td><td style="padding:8px 12px;border-bottom:1px solid #e8e4e6;color:#6A4858;">${a.owner||'TBD'}</td><td style="padding:8px 12px;border-bottom:1px solid #e8e4e6;">${a.deadline||'TBD'}</td></tr>`).join('');
const decisionItems = (d.decisions || []).map(dec => `<li style="margin-bottom:6px;">${dec}</li>`).join('');
const topicTags = (d.key_topics || []).map(t => `<span style="display:inline-block;background:#F2EEF0;color:#36262C;font-family:monospace;font-size:11px;letter-spacing:.1em;text-transform:uppercase;padding:3px 8px;border-radius:3px;margin:2px;">${t}</span>`).join('');
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;background:#F9F7F8;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;"><div style="max-width:640px;margin:32px auto;background:#ffffff;border:1px solid rgba(28,22,24,0.10);border-radius:3px;overflow:hidden;"><div style="background:#1C1618;padding:28px 32px;"><div style="font-family:Georgia,serif;font-size:22px;color:#F9F7F8;letter-spacing:-.025em;">C<span style="color:#7D5569;">ur</span>cible<span style="color:#7D5569;">.</span></div><div style="color:#CCBEC2;font-size:12px;font-family:monospace;letter-spacing:.16em;text-transform:uppercase;margin-top:4px;">MeetCore™ — Meeting Summary</div></div><div style="padding:32px;"><div style="margin-bottom:4px;"><span style="font-size:18px;">${platformIcon}</span> <span style="font-family:monospace;font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:#847278;">${platformLabel}</span></div><h1 style="margin:0 0 4px;font-size:24px;font-weight:400;color:#1C1618;letter-spacing:-.025em;font-family:Georgia,serif;">${d.topic||'Meeting Summary'}</h1><p style="margin:0 0 24px;color:#847278;font-size:13px;">${new Date(d.start_time).toLocaleString('en-US',{dateStyle:'full',timeStyle:'short'})} · Host: ${d.host||'—'}</p><div style="margin-bottom:4px;">${topicTags}</div><hr style="border:none;border-top:1px solid rgba(28,22,24,0.06);margin:24px 0;"><h2 style="font-size:14px;font-family:monospace;letter-spacing:.12em;text-transform:uppercase;color:#847278;margin:0 0 12px;">Summary</h2><p style="margin:0 0 24px;color:#36262C;line-height:1.7;">${d.summary||''}</p>${decisionItems?`<h2 style="font-size:14px;font-family:monospace;letter-spacing:.12em;text-transform:uppercase;color:#847278;margin:0 0 12px;">Decisions</h2><ul style="margin:0 0 24px;padding-left:20px;color:#36262C;line-height:1.7;">${decisionItems}</ul>`:''  }${actionRows?`<h2 style="font-size:14px;font-family:monospace;letter-spacing:.12em;text-transform:uppercase;color:#847278;margin:0 0 12px;">Action Items</h2><table style="width:100%;border-collapse:collapse;margin-bottom:24px;"><thead><tr style="background:#F2EEF0;"><th style="padding:8px 12px;text-align:left;font-size:11px;font-family:monospace;letter-spacing:.1em;text-transform:uppercase;color:#847278;">Task</th><th style="padding:8px 12px;text-align:left;font-size:11px;font-family:monospace;letter-spacing:.1em;text-transform:uppercase;color:#847278;">Owner</th><th style="padding:8px 12px;text-align:left;font-size:11px;font-family:monospace;letter-spacing:.1em;text-transform:uppercase;color:#847278;">Deadline</th></tr></thead><tbody>${actionRows}</tbody></table>`:''  }${d.follow_up_required?`<div style="background:rgba(106,72,88,0.07);border-left:3px solid #6A4858;padding:16px;border-radius:3px;"><p style="margin:0;color:#36262C;font-size:13px;"><strong style="color:#6A4858;">Follow-up required:</strong> ${d.follow_up_notes||''}</p></div>`:''  }</div><div style="padding:16px 32px;border-top:1px solid rgba(28,22,24,0.06);background:#F2EEF0;"><p style="margin:0;font-size:11px;color:#847278;font-family:monospace;letter-spacing:.08em;">CURCIBLE MEETCORE™ · AUTO-GENERATED · DO NOT REPLY</p></div></div></body></html>`;
return [{json: {html, subject: `[MeetCore] ${d.topic||'Meeting'} — ${platformLabel} · ${new Date(d.start_time).toLocaleDateString()}`, follow_up_required: d.follow_up_required, follow_up_notes: d.follow_up_notes, topic: d.topic, start_time: d.start_time}}];
